mapper.delete:
DELETE FROM energy_summaries
WHERE summary_type = #{summaryType}
  AND summary_at >= #{from}
  AND summary_at < #{to}

mapper.select:
SELECT id, plant_id, facility_id, measured_at, electricity_kwh, gas_m3, water_ton, solar_kwh, peak_kw, created_at
FROM energy_measurements

    AND plant_id = #{plantId}
    AND facility_id = #{facilityId}
    AND measured_at >= #{from}
    AND measured_at <= #{to}

ORDER BY measured_at DESC, id DESC
LIMIT #{limit}

SELECT id, plant_id, facility_id, summary_type, summary_at, electricity_kwh, gas_m3, water_ton, solar_kwh, peak_kw, carbon_emission
FROM energy_summaries

    AND plant_id = #{plantId}


            AND facility_id = #{facilityId}


            AND facility_id IS NULL


    AND summary_type = #{summaryType}
    AND summary_at >= #{from}
    AND summary_at <= #{to}

ORDER BY summary_at ASC, id ASC

WITH ordered_measurements AS ( SELECT id, plant_id, facility_id, measured_at, DATE(measured_at) AS measured_date, electricity_kwh, gas_m3, water_ton, solar_kwh, peak_kw, LAG(electricity_kwh) OVER ( PARTITION BY plant_id, facility_id, DATE(measured_at) ORDER BY measured_at ASC, id ASC ) AS previous_electricity_kwh, LAG(gas_m3) OVER ( PARTITION BY plant_id, facility_id, DATE(measured_at) ORDER BY measured_at ASC, id ASC ) AS previous_gas_m3, LAG(water_ton) OVER ( PARTITION BY plant_id, facility_id, DATE(measured_at) ORDER BY measured_at ASC, id ASC ) AS previous_water_ton, LAG(solar_kwh) OVER ( PARTITION BY plant_id, facility_id, DATE(measured_at) ORDER BY measured_at ASC, id ASC ) AS previous_solar_kwh FROM energy_measurements
AND plant_id = #{plantId} AND facility_id = #{facilityId} AND measured_at >= #{from} AND measured_at <= #{to}
) SELECT NULL AS id, plant_id, facility_id, 'DAILY' AS summary_type, CAST(measured_date AS DATETIME) AS summary_at, COALESCE(SUM( CASE WHEN previous_electricity_kwh IS NULL THEN 0 WHEN electricity_kwh >= previous_electricity_kwh THEN electricity_kwh - previous_electricity_kwh ELSE 0 END ), 0) AS electricity_kwh, COALESCE(SUM( CASE WHEN previous_gas_m3 IS NULL THEN 0 WHEN gas_m3 >= previous_gas_m3 THEN gas_m3 - previous_gas_m3 ELSE 0 END ), 0) AS gas_m3, COALESCE(SUM( CASE WHEN previous_water_ton IS NULL THEN 0 WHEN water_ton >= previous_water_ton THEN water_ton - previous_water_ton ELSE 0 END ), 0) AS water_ton, COALESCE(SUM( CASE WHEN previous_solar_kwh IS NULL THEN 0 WHEN solar_kwh >= previous_solar_kwh THEN solar_kwh - previous_solar_kwh ELSE 0 END ), 0) AS solar_kwh, COALESCE(MAX(peak_kw), 0) AS peak_kw, NULL AS carbon_emission FROM ordered_measurements GROUP BY plant_id, facility_id, measured_date ORDER BY summary_at ASC

SELECT id, plant_id, facility_id, measured_at, electricity_kwh, gas_m3, water_ton, solar_kwh, peak_kw, created_at
FROM energy_measurements
WHERE plant_id = #{plantId}
  AND facility_id = #{facilityId}
ORDER BY measured_at DESC, id DESC
LIMIT 1
